import React from "react";
// Import the pretty version you just finished
import EeshaWalkComponent from "../components/EeshaWalkComponent"; 

const WalkScreen = ({ audioCtx, soundType, onStop }) => {
  return (
    <div className="walk-screen-container">
      {/* This calls the pretty component from the components folder */}
      <EeshaWalkComponent 
        audioCtx={audioCtx} 
        soundType={soundType} 
        onStop={onStop} 
      />
    </div>
  );
};

export default WalkScreen;
